import { PriorityQueue } from 'typescript-collections';

function solve(m: number, n: number, waitCost: number[][]): number {
    const INF = Infinity;
    const dist = Array(m).fill(0).map(() => Array(n).fill(0).map(() => Array(2).fill(INF)));
    dist[0][0][1] = 1; // Starting at (0,0) with odd time (1)

    const pq = new PriorityQueue<[number, number, number, number]>((a, b) => a[0] - b[0]);
    pq.enqueue([1, 0, 0, 1]);

    const directions = [[0, 1], [1, 0]]; // Right, Down

    while (!pq.isEmpty()) {
        const [cost, i, j, parity] = pq.dequeue()!;

        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        if (cost > dist[i][j][parity]) {
            continue;
        }

        if (parity === 1) { // Odd time: move
            for (const [dx, dy] of directions) {
                const ni = i + dx;
                const nj = j + dy;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    const newCost = cost + (ni + 1) * (nj + 1);
                    if (newCost < dist[ni][nj][0]) {
                        dist[ni][nj][0] = newCost;
                        pq.enqueue([newCost, ni, nj, 0]);
                    }
                }
            }
        } else { // Even time: wait
            const newCost = cost + waitCost[i][j];
            if (newCost < dist[i][j][1]) {
                dist[i][j][1] = newCost;
                pq.enqueue([newCost, i, j, 1]);
            }
        }
    }

    return -1; // Should not reach here
}

